import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o,c as n,d as r,a as e,e as s}from"./app-85df9ac8.js";const t="/assets/images/acomm-agent.gif",i={},l=e("p",null,"La interfaz está cambiando, el browser deja de ser el centro del universo. Esto parece un pensamiento recurrente estos últimos meses.",-1),c=e("blockquote",null,[e("p",null,"Dave Bowman: Open the pod bay doors, HAL."),e("p",null,"HAL 9000: I'm sorry, Dave. I'm afraid I can't do that.")],-1),d=s(`<h2 id="agente-agente" tabindex="-1"><a class="header-anchor" href="#agente-agente" aria-hidden="true">#</a> Agente, agente...</h2><p>Hace un tiempo resuena en mi cabeza la idea de que la forma en que interactuamos con el software está cambiando.</p><p>Para nosotros, los desarrolladores, este cambio ya es tangible: la forma en que pensamos, las herramientas que utilizamos y la manera en la que resolvemos problemas han cambiado.</p><p>Este nuevo ente llamado &quot;agente&quot; se ha convertido en nuestro centro gravitatorio y ha tomado el control de nuestro día a día.</p><p>¿Cuánto tiempo llevará para que esta dinámica se extienda más allá de nuestro ámbito?</p><p>¿Pediremos a nuestro agente personal que busque en internet las mejores ofertas disponibles en los supermercados cercanos y que organice la entrega para la hora de llegada a casa?</p><p>¿En breve seremos capaces de transferirle dinero a nuestro amigo, quién pagó la cena, pidiéndole a nuestro agente personal que acceda por nosotros y realice la transacción en nuestro home banking?</p><p>De forma sencilla, podemos decir que un agente es un bucle <code>for</code> que invoca recurrentemente a un modelo de lenguaje y que está provisto de una serie de herramientas para interactuar con su entorno. En cada iteración, este bucle verifica si el modelo le indica utilizar alguna herramienta o si debe devolver al cliente una respuesta final.</p><p>Un agente complejo se encarga de gestionar el contexto que es enviado al modelo: inyectando el prompt del sistema, decidiendo qué <code>skill</code> es relevante para la tarea a realizar o compactándolo una vez alcanzado el tamaño máximo permitido. Además, es capaz de instanciar subagentes y delegarles tareas específicas en paralelo mientras coordina la tarea general.</p><p>Tanto el agente principal como los subagentes interactúan con su entorno a través de herramientas o <code>tools</code>, mediante lo que se conoce como <code>tool_calling</code>. Si no me equivoco, el término <code>tool_calling</code> proviene del framework LangChain, donde esta abstracción permitía inyectarle al servicio la posibilidad de ejecutar código definido por el usuario. En estos nuevos agentes, las <code>tools</code> hoy van más allá del propio código del agente y le permiten interactuar con archivos locales, bases de datos o servidores externos.</p><h2 id="mcp" tabindex="-1"><a class="header-anchor" href="#mcp" aria-hidden="true">#</a> MCP</h2><p>Hoy en día, las plataformas con las que interactuamos suelen brindar una aplicación que corre en nuestro navegador y un conjunto de APIs para comunicarse con el servidor remoto.</p><p>En esta nueva era, el agente será la interfaz con el cliente, mientras que las plataformas deberán proveer un set de herramientas para exponer su funcionalidad y el acceso a sus datos. Es aquí donde el protocolo MCP (Model Context Protocol) entra en juego: es la forma actual con la cual extendemos las capacidades iniciales de los agentes.</p><p>MCP es un protocolo estándar abierto que define cómo las aplicaciones operan sobre componentes externos. Básicamente, se encarga de estandarizar una arquitectura &quot;cliente-servidor&quot; entre el agente (el cliente MCP) y las plataformas a las que queremos que acceda (el servidor MCP).</p><p>Un servidor MCP expone de tres componentes clave:</p><ul><li><strong>Recursos (Resources):</strong> Datos con formato similar a un archivo que el servidor expone de forma estática para que el agente los pueda leer (por ejemplo, la documentación de la empresa, métricas o el esquema de una base de datos).</li><li><strong>Herramientas (Tools):</strong> Funciones o tareas específicas orientadas a la acción que corren del lado del servidor y que el agente puede invocar libremente a voluntad.</li><li><strong>Prompts:</strong> Plantillas prediseñadas que ayudan a enviar instrucciones más precisas al LLM desde el cliente.</li></ul><h2 id="acomm" tabindex="-1"><a class="header-anchor" href="#acomm" aria-hidden="true">#</a> Acomm</h2><p>En pos de materializar de alguna forma estas ideas, me decidí a crear un agente personalizado con ayuda de Antigravity.</p><p>Disponía de un servicio de juguete implementado para un round de entrevistas: una tienda de productos escrita en Golang. Debía crear la interfaz de usuario, el agente gestor y wrappear la aplicación de la tienda con un servidor MCP para habilitar la comunicación.</p><h4 id="descarga-el-repo" tabindex="-1"><a class="header-anchor" href="#descarga-el-repo" aria-hidden="true">#</a> Descargá el repo</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> clone https://github.com/leandrogutierrez148/acomm
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="run" tabindex="-1"><a class="header-anchor" href="#run" aria-hidden="true">#</a> Run</h4><p>Asegurate de tener <code>docker</code> instalado y corriendo.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">make</span> up
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Andá a <code>http://localhost:8501</code></p><figure><img src="`+t+'" alt="agent workflow" tabindex="0" loading="lazy"><figcaption>agent workflow</figcaption></figure><h2 id="nota-al-pie-modelos-como-commodities" tabindex="-1"><a class="header-anchor" href="#nota-al-pie-modelos-como-commodities" aria-hidden="true">#</a> Nota al pie: modelos como commodities</h2><p>La forma en que interactuamos con la inteligencia artificial está cambiando. Ya no es solo un chatbot; ahora navega por vos, ejecuta acciones, sugiere decisiones de negocio, etc. Mientras esto sucede, comienza a proveerse un servicio hasta ahora desconocido: la inferencia en tiempo real; de esta forma, el modelo se convierte en un commodity. De repente hay un &quot;layer&quot; nuevo en la arquitectura cliente/servidor: <strong>cliente/LLM/servidor</strong>. El costo del procesamiento que antes recaía sobre las máquinas del proveedor, ahora recae sobre el modelo de inferencia y finalmente vuelve a ser pagado por el cliente.</p>',28);function u(m,p){return o(),n("div",null,[l,c,r(" more "),d])}const v=a(i,[["render",u],["__file","agentic-workflows-mcp.html.vue"]]);export{v as default};
